import { describe, it, expect } from 'vitest';
import {
  aeonMonitorCandidatePaths,
  findExecutableAeonMonitor,
  probeAeonMonitor,
} from './aeon-monitor-probe.js';

describe('aeon-monitor-probe', () => {
  const root = '/tmp/gnosis-fake-root';

  it('uses a single path when explicit bin is set', () => {
    const paths = aeonMonitorCandidatePaths(root, '/opt/aeon-monitor');
    expect(paths).toEqual(['/opt/aeon-monitor']);
  });

  it('defaults to distributed-inference and gnosis release paths', () => {
    const paths = aeonMonitorCandidatePaths(root, null);
    expect(paths).toHaveLength(2);
    expect(paths[0]).toContain('distributed-inference/target/release/aeon-monitor');
    expect(paths[1]).toContain(`${root}/target/release/aeon-monitor`);
  });

  it('probe marks nativeBackendReady false when nothing is executable', () => {
    const r = probeAeonMonitor(root, null);
    expect(r.nativeBackendReady).toBe(false);
    expect(r.resolvedExecutable).toBeNull();
    expect(r.candidates.every((c) => !c.executable)).toBe(true);
  });

  it('findExecutable returns null for missing tree', () => {
    expect(findExecutableAeonMonitor(root, null)).toBeNull();
  });
});
